private boolean isSafeReplacement(Node node, Node replacement) {
    // Check if node is a name node.
    if (node.isName()) {
        return true;
    }

    // Preconditions check for get prop node.
    Preconditions.checkArgument(node.isGetProp());

    // Handle first child node. If not a name node, return false.
    Node childNode = node.getFirstChild();
    if (!childNode.isName()) {
        return false;
    }

    // Check if first child node is a name node and is assigned to a value.
    if (childNode.isName() && isNameAssignedTo(childNode.getString(), replacement)) {
        return false;
    }

    // Return true if all checks pass.
    return true;
}
